"""File table component for displaying directory listings."""

import logging
from dataclasses import dataclass
from datetime import datetime
from pathlib import Path
from typing import Optional

from textual.widgets import DataTable

logger = logging.getLogger("termzilla")


@dataclass
class FileEntry:
    """Metadata for a single row in the file table."""
    name: str
    path: str
    is_dir: bool
    size: int = 0
    modified: float = 0.0


class FileTable(DataTable):
    """A DataTable for displaying file/directory listings."""

    def __init__(self, id: Optional[str] = None) -> None:
        super().__init__(id=id)
        self.current_path: str = str(Path.home())
        self.show_hidden: bool = False
        self._entries: list[FileEntry] = []

    def on_mount(self) -> None:
        """Set up columns when mounted."""
        self.add_columns("Name", "Size", "Modified")
        self.cursor_type = "row"
        self.zebra_stripes = True

    def load_local_directory(self, path: str) -> None:
        """Load and display a local directory."""
        self.clear()
        self._entries.clear()
        self.current_path = str(Path(path).resolve())

        # Parent directory
        parent = str(Path(self.current_path).parent)
        self._entries.append(FileEntry(name="..", path=parent, is_dir=True))
        self.add_row("[..]", "", "")

        try:
            items = sorted(
                Path(self.current_path).iterdir(),
                key=lambda p: (not p.is_dir(), p.name.lower()),
            )
            for entry in items:
                if entry.name.startswith(".") and not self.show_hidden:
                    continue
                try:
                    stat = entry.stat()
                    is_dir = entry.is_dir()
                    size = self._format_size(stat.st_size) if not is_dir else "<DIR>"
                    modified = datetime.fromtimestamp(stat.st_mtime).strftime("%Y-%m-%d %H:%M")
                    prefix = "/" if is_dir else " "
                    self._entries.append(FileEntry(
                        name=entry.name,
                        path=str(entry),
                        is_dir=is_dir,
                        size=stat.st_size,
                        modified=stat.st_mtime,
                    ))
                    self.add_row(f"{prefix}{entry.name}", size, modified)
                except PermissionError:
                    self._entries.append(FileEntry(name=entry.name, path=str(entry), is_dir=False))
                    self.add_row(f" {entry.name}", "no access", "")
        except PermissionError:
            pass
        except Exception as e:
            logger.error(f"Error loading directory: {e}")

    def load_remote_directory(self, sftp_client, path: str) -> None:
        """Load and display a remote directory via SFTP."""
        from stat import S_ISDIR

        self.clear()
        self._entries.clear()

        try:
            self.current_path = sftp_client.normalize(path)
            entries = sftp_client.listdir_attr(self.current_path)
            entries_sorted = sorted(entries, key=lambda e: e.filename.lower())

            # Parent directory
            parent = str(Path(self.current_path).parent)
            self._entries.append(FileEntry(name="..", path=parent, is_dir=True))
            self.add_row("[..]", "", "")

            for entry in entries_sorted:
                if entry.filename.startswith(".") and not self.show_hidden:
                    continue

                mode = entry.st_mode if entry.st_mode else 0
                is_dir = S_ISDIR(mode)
                size = self._format_size(entry.st_size) if entry.st_size and not is_dir else ("<DIR>" if is_dir else "0 B")
                mtime = entry.st_mtime or 0
                modified = datetime.fromtimestamp(mtime).strftime("%Y-%m-%d %H:%M") if mtime else ""
                entry_path = f"{self.current_path.rstrip('/')}/{entry.filename}"
                prefix = "/" if is_dir else " "

                self._entries.append(FileEntry(
                    name=entry.filename,
                    path=entry_path,
                    is_dir=is_dir,
                    size=entry.st_size or 0,
                    modified=mtime,
                ))
                self.add_row(f"{prefix}{entry.filename}", size, modified)

        except Exception as e:
            logger.error(f"Error loading remote directory: {e}")

    def get_selected_entry(self) -> Optional[FileEntry]:
        """Get the FileEntry for the currently selected row."""
        row = self.cursor_row
        if row is None or row < 0 or row >= len(self._entries):
            return None
        return self._entries[row]

    def get_selected_path(self) -> Optional[str]:
        """Get the path of the currently selected row."""
        entry = self.get_selected_entry()
        return entry.path if entry else None

    def is_selected_directory(self) -> bool:
        """Check if the selected row is a directory."""
        entry = self.get_selected_entry()
        return entry.is_dir if entry else False

    def get_selected_name(self) -> Optional[str]:
        """Get the name of the currently selected file/dir."""
        entry = self.get_selected_entry()
        return entry.name if entry else None

    def toggle_hidden_files(self) -> None:
        """Toggle showing hidden files."""
        self.show_hidden = not self.show_hidden

    @staticmethod
    def _format_size(size_bytes) -> str:
        """Format file size in human-readable format."""
        try:
            size_bytes = int(size_bytes)
        except (ValueError, TypeError):
            return "-"
        for unit in ("B", "KB", "MB", "GB", "TB"):
            if size_bytes < 1024:
                return f"{size_bytes:.0f} {unit}" if unit == "B" else f"{size_bytes:.1f} {unit}"
            size_bytes /= 1024
        return f"{size_bytes:.1f} PB"
